workflow-item.script:
var restClient = vcfHost.createRestClient();
var refreshToken = vcfHost.getApiToken();


var bodyWithRefresh = JSON.stringify({ "refreshToken": refreshToken });
var bodyEmpty = null;

var tests = [
    { method: "POST", path: "/iaas/api/login",                                          body: bodyWithRefresh },
    { method: "POST", path: "/csp/gateway/am/api/auth/api-tokens/authorize",            body: "api_token=" + refreshToken },
    { method: "POST", path: "/api/tokens",                                              body: bodyWithRefresh },
    { method: "POST", path: "/csp/gateway/am/api/login?access_token",                  body: bodyWithRefresh },
    { method: "GET",  path: "/csp/gateway/am/api/auth/token-public-key?issuer=authn",  body: null },
    { method: "POST", path: "/identity/api/tokens",                                     body: bodyWithRefresh },
    { method: "POST", path: "/vcac/services/api/tokens",                                body: bodyWithRefresh },
];

for each (var t in tests) {
    var req = restClient.createRequest(t.method, t.path, t.body);
    req.setHeader("Accept", "application/json");
    if (t.body && t.body.indexOf("{") === 0) {
        req.setHeader("Content-Type", "application/json");
    } else {
        req.setHeader("Content-Type", "application/x-www-form-urlencoded");
    }

    var res = restClient.execute(req);
    System.log("[" + res.getStatusCode() + "] " + t.method + " " + t.path);

    // Print body only for non-404 responses
    if (res.getStatusCode() !== 404) {
        System.log("  --> " + res.getContentAsString());
    }
}
